Here's how to use MSTest's comparison assertions for your `ScoreCalculator`:

## Comparison Assertions

```csharp
// Assert a value exceeds a lower bound
Assert.IsGreaterThan(lowerBound, actual);

// Assert a value is below an upper bound
Assert.IsLessThan(upperBound, actual);

// Assert a value falls within [low, high]
Assert.IsInRange(actual, low, high);
```

## Test Class for ScoreCalculator

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(5, 10, 50.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(3, 4, 75.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_MidRange_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(50, 200);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_AnyValidInput_IsInRange()
    {
        var result = _calculator.NormalizeScore(75, 100);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

## Key Takeaways

| Assertion | Use Case |
|-----------|----------|
| `Assert.IsGreaterThan(0.0, result)` | Score must be positive |
| `Assert.IsLessThan(100.0, result)` | Score below a cap |
| `Assert.IsInRange(result, 0.0, 100.0)` | Score within valid bounds |

These give far better failure messages than `Assert.IsTrue(result > 0)` — on failure they report the actual value and the bound that was violated. Use `[DataRow]` at boundaries (e.g., 89.9 vs 90.0) to catch off-by-one errors in your grade logic.
